import{_ as a,o,c as s,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"macOS IPC","description":"","frontmatter":{"summary":"macOS IPC architecture for OpenSoul app, gateway node transport, and PeekabooBridge","read_when":["Editing IPC contracts or menu bar app IPC"],"title":"macOS IPC"},"headers":[],"relativePath":"platforms/mac/xpc.md","filePath":"platforms/mac/xpc.md","lastUpdated":null}'),t={name:"platforms/mac/xpc.md"};function i(r,e,l,c,d,p){return o(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="opensoul-macos-ipc-architecture" tabindex="-1"><a class="header-anchor" href="#opensoul-macos-ipc-architecture">#</a> OpenSoul macOS IPC architecture</h1><p><strong>Current model:</strong> a local Unix socket connects the <strong>node host service</strong> to the <strong>macOS app</strong> for exec approvals + <code>system.run</code>. A <code>opensoul-mac</code> debug CLI exists for discovery/connect checks; agent actions still flow through the Gateway WebSocket and <code>node.invoke</code>. UI automation uses PeekabooBridge.</p><h2 id="goals" tabindex="-1"><a class="header-anchor" href="#goals">#</a> Goals</h2><ul><li>Single GUI app instance that owns all TCC-facing work (notifications, screen recording, mic, speech, AppleScript).</li><li>A small surface for automation: Gateway + node commands, plus PeekabooBridge for UI automation.</li><li>Predictable permissions: always the same signed bundle ID, launched by launchd, so TCC grants stick.</li></ul><h2 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works">#</a> How it works</h2><h3 id="gateway-node-transport" tabindex="-1"><a class="header-anchor" href="#gateway-node-transport">#</a> Gateway + node transport</h3><ul><li>The app runs the Gateway (local mode) and connects to it as a node.</li><li>Agent actions are performed via <code>node.invoke</code> (e.g. <code>system.run</code>, <code>system.notify</code>, <code>canvas.*</code>).</li></ul><h3 id="node-service-app-ipc" tabindex="-1"><a class="header-anchor" href="#node-service-app-ipc">#</a> Node service + app IPC</h3><ul><li>A headless node host service connects to the Gateway WebSocket.</li><li><code>system.run</code> requests are forwarded to the macOS app over a local Unix socket.</li><li>The app performs the exec in UI context, prompts if needed, and returns output.</li></ul><p>Diagram (SCI):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent -&gt; Gateway -&gt; Node Service (WS)</span></span>
<span class="line"><span>                      |  IPC (UDS + token + HMAC + TTL)</span></span>
<span class="line"><span>                      v</span></span>
<span class="line"><span>                  Mac App (UI + TCC + system.run)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="peekaboobridge-ui-automation" tabindex="-1"><a class="header-anchor" href="#peekaboobridge-ui-automation">#</a> PeekabooBridge (UI automation)</h3><ul><li>UI automation uses a separate UNIX socket named <code>bridge.sock</code> and the PeekabooBridge JSON protocol.</li><li>Host preference order (client-side): Peekaboo.app → Claude.app → OpenSoul.app → local execution.</li><li>Security: bridge hosts require an allowed TeamID; DEBUG-only same-UID escape hatch is guarded by <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> (Peekaboo convention).</li><li>See: <a href="/docs/platforms/mac/peekaboo">PeekabooBridge usage</a> for details.</li></ul><h2 id="operational-flows" tabindex="-1"><a class="header-anchor" href="#operational-flows">#</a> Operational flows</h2><ul><li>Restart/rebuild: <code>SIGN_IDENTITY=&quot;Apple Development: &lt;Developer Name&gt; (&lt;TEAMID&gt;)&quot; scripts/restart-mac.sh</code><ul><li>Kills existing instances</li><li>Swift build + package</li><li>Writes/bootstraps/kickstarts the LaunchAgent</li></ul></li><li>Single instance: app exits early if another instance with the same bundle ID is running.</li></ul><h2 id="hardening-notes" tabindex="-1"><a class="header-anchor" href="#hardening-notes">#</a> Hardening notes</h2><ul><li>Prefer requiring a TeamID match for all privileged surfaces.</li><li>PeekabooBridge: <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> (DEBUG-only) may allow same-UID callers for local development.</li><li>All communication remains local-only; no network sockets are exposed.</li><li>TCC prompts originate only from the GUI app bundle; keep the signed bundle ID stable across rebuilds.</li><li>IPC hardening: socket mode <code>0600</code>, token, peer-UID checks, HMAC challenge/response, short TTL.</li></ul>`,17)])])}const m=a(t,[["render",i]]);export{u as __pageData,m as default};
